function norm(s){ if(s==null)return''; s=String(s).normalize('NFD').replace(/[̀-ͯ]/g,''); s=s.toLowerCase().replace(/ς/g,'σ'); s=s.replace(/[^Ͱ-Ͽἀ-῿a-z]/gi,''); return s; }
function accepts(val,accept,canon){ var n=norm(val); if(!n)return false; var L=(accept||[]).concat(canon?[canon]:[]); for(var i=0;i<L.length;i++){ if(norm(L[i])===n)return true; } return false; }
var MKEY='gsuite-mastery-v1';
