function record(pair,ok){ if(!pair)return; var m=mast(),e=m[pair]||{right:0,wrong:0,seen:false}; if(!e.seen){ if(ok)e.right++; else e.wrong++; e.seen=true;} m[pair]=e; try{localStorage.setItem(MKEY,JSON.stringify(m));}catch(e2){} paintDuel(); }
function weakCount(){ var m=mast(),c=0; for(var k in m){ if(m[k].wrong>0)c++; } return c; }

